function neighborsOf(cell: Cell): Cell[] {
  const neighbors: Cell[] = [];
  for (let dRow = -1; dRow <= 1; dRow++) {
    for (let dCol = -1; dCol <= 1; dCol++) {
      if (dRow !== 0 || dCol !== 0) {
        neighbors.push([cell[0] + dRow, cell[1] + dCol]);
      }
    }
  }
  return neighbors;
}

export function nextGeneration(liveCells: Cell[]): Cell[] {
  const countNeighbors = (cell: Cell): number =>
    liveCells.filter((other) => isNeighbor(other, cell)).length;

  const isLive = (cell: Cell): boolean =>
    liveCells.some((other) => cellEquals(other, cell));

  const survivors = liveCells.filter((cell) => {
    const neighbors = countNeighbors(cell);
    return neighbors === 2 || neighbors === 3;
  });

  const deadCandidates = liveCells.flatMap(neighborsOf).filter(
    (candidate, index, all) =>
      !isLive(candidate) &&
      all.findIndex((other) => cellEquals(other, candidate)) === index
  );

  const births = deadCandidates.filter(
    (candidate) => countNeighbors(candidate) === 3
  );

  return [...survivors, ...births];
}

